+# Data Models and Schemas
+## Benchmarking System Data Structures
+
+**Version:** 1.0.0
+**Date:** 2025-11-09
+
+---
+
+## Core Data Models
+
+### 1. Benchmark Configuration
+
+```typescript
+interface BenchmarkConfig {
+  // Metadata
+  id: string;
+  name: string;
+  description: string;
+  version: string;
+  createdAt: string;
+
+  // Execution settings
+  execution: {
+    iterations: number; // Number of runs per test
+    warmupRuns: number; // Runs to discard before measurement
+    timeout: number; // Max time per test (ms)
+    parallelism: number; // Max concurrent tests
+    randomSeed?: number; // For reproducibility
+  };
+
+  // Environment configuration
+  environment: {
+    docker: {
+      baseImages: {
+        jujutsu: string;
+        git: string;
+        gitWorktrees: string;
+      };
+      resources: ResourceConstraints;
+      network: 'none' | 'bridge' | 'host';
+      volumes: VolumeMount[];
+    };
+  };
+
+  // Test selection
+  tests: {
+    suites: string[]; // Suite names or patterns
+    include?: string[]; // Specific test IDs
+    exclude?: string[]; // Tests to skip
+    tags?: string[]; // Filter by tags
+  };
+
+  // Data generation
+  dataGeneration: {
+    repoSizes: ('small' | 'medium' | 'large')[];
+    customFixtures?: string[]; // Paths to custom repos
+    cacheFixtures: boolean;
+  };
+
+  // Output settings
+  output: {
+    formats: ('json' | 'markdown' | 'html')[];
+    destination: string;
+    archiveResults: boolean;
+    compression: boolean;
+  };
+
+  // Analysis options
+  analysis: {
+    statisticalSignificance: number; // p-value threshold
+    confidenceLevel: number; // e.g., 0.95
+    outlierDetection: boolean;
+    trendAnalysis: boolean;
+  };
+
+  // Learning integration
+  agentdb: {
+    enabled: boolean;
+    sessionId: string;
+    storePatterns: boolean;
+    queryHistorical: boolean;
+  };
+}
+
+interface ResourceConstraints {
+  cpus: number; // Number of CPU cores
+  memory: number; // Memory in bytes
+  memoryReservation: number; // Soft limit
+  diskQuota?: number; // Disk space limit
+  ioWeight?: number; // I/O priority (10-1000)
+}
+
+interface VolumeMount {
+  source: string; // Host path
+  target: string; // Container path
+  readonly: boolean;
+}
+```
+
+### 2. Test Suite Definition
+
+```typescript
+interface TestSuite {
+  // Metadata
+  id: string;
+  name: string;
+  description: string;
+  category: TestCategory;
+  tags: string[];
+
+  // Test configuration
+  tests: Test[];
+  setup?: SetupScript;
+  teardown?: TeardownScript;
+
+  // Requirements
+  requirements: {
+    minRepoSize: RepoSize;
+    requiredFeatures: string[];
+    estimatedDuration: number; // ms
+  };
+}
+
+type TestCategory =
+  | 'basic-operations'
+  | 'workflow-simulation'
+  | 'scale-testing'
+  | 'edge-cases';
+
+type RepoSize = 'small' | 'medium' | 'large' | 'custom';
+
+interface Test {
+  id: string;
+  name: string;
+  description: string;
+
+  // Execution
+  command: string; // Command to run
+  expectedExitCode: number;
+  timeout: number; // Override default timeout
+
+  // Variants
+  vcsTypes: ('jujutsu' | 'git' | 'git-worktrees')[];
+
+  // Metrics to collect
+  metrics: MetricType[];
+
+  // Validation
+  validation?: {
+    outputMatches?: RegExp;
+    minExecutionTime?: number;
+    maxExecutionTime?: number;
+    maxMemoryUsage?: number;
+  };
+
+  // Dependencies
+  dependsOn?: string[]; // Test IDs that must run first
+}
+
+type MetricType =
+  | 'execution-time'
+  | 'cpu-usage'
+  | 'memory-usage'
+  | 'io-operations'
+  | 'disk-usage'
+  | 'network-traffic';
+
+interface SetupScript {
+  description: string;
+  commands: string[];
+  timeout: number;
+}
+
+interface TeardownScript {
+  description: string;
+  commands: string[];
+  alwaysRun: boolean; // Run even on failure
+}
+```
+
+### 3. Repository Fixture
+
+```typescript
+interface RepositoryFixture {
+  // Metadata
+  id: string;
+  name: string;
+  size: RepoSize;
+  createdAt: string;
+
+  // Location
+  path: string; // Absolute path to repository
+  vcsType: 'jujutsu' | 'git';
+
+  // Repository properties
+  metadata: {
+    commits: number;
+    branches: number;
+    tags: number;
+    files: number;
+    totalSize: number; // bytes
+    largestFile: number; // bytes
+  };
+
+  // Content characteristics
+  characteristics: {
+    codeFiles: number;
+    binaryFiles: number;
+    avgCommitSize: number;
+    avgBranchDepth: number;
+    conflictFrequency: number; // 0-1
+  };
+
+  // Generation info
+  generation: {
+    strategy: 'realistic' | 'synthetic' | 'imported';
+    seed: number; // For reproducibility
+    parameters: GenerationParameters;
+  };
+}
+
+interface GenerationParameters {
+  // Repository structure
+  fileTree: {
+    maxDepth: number;
+    filesPerDir: number;
+    dirCount: number;
+  };
+
+  // Commit history
+  commits: {
+    count: number;
+    timeSpan: number; // days
+    authorsCount: number;
+    avgFilesPerCommit: number;
+  };
+
+  // Branching structure
+  branches: {
+    count: number;
+    mergeFrequency: number; // 0-1
+    branchLifetime: number; // commits
+  };
+
+  // Content
+  content: {
+    codeLanguages: string[];
+    avgFileSize: number;
+    binaryRatio: number; // 0-1
+  };
+}
+```
+
+### 4. Raw Metrics
+
+```typescript
+interface RawMetric {
+  // Test identification
+  testId: string;
+  runId: string; // Unique ID for this specific run
+  iteration: number; // Which iteration (1-N)
+  timestamp: string; // ISO 8601
+
+  // Test context
+  context: {
+    vcsType: 'jujutsu' | 'git' | 'git-worktrees';
+    operation: string;
+    repoSize: RepoSize;
+    repoId: string;
+  };
+
+  // Execution results
+  execution: {
+    exitCode: number;
+    signalCode?: string;
+    stdout: string;
+    stderr: string;
+    startTime: number; // Unix timestamp ms
+    endTime: number; // Unix timestamp ms
+    durationMs: number;
+  };
+
+  // Performance metrics
+  performance: {
+    cpu: CPUMetrics;
+    memory: MemoryMetrics;
+    io: IOMetrics;
+    disk: DiskMetrics;
+  };
+
+  // Environment snapshot
+  environment: {
+    containerId: string;
+    cpuCores: number;
+    totalMemory: number;
+    diskType: string;
+    kernelVersion: string;
+  };
+
+  // Quality indicators
+  quality: {
+    success: boolean;
+    errorType?: string;
+    warningCount: number;
+    retryCount: number;
+  };
+}
+
+interface CPUMetrics {
+  userTime: number; // ms
+  systemTime: number; // ms
+  totalTime: number; // ms
+  percentage: number; // 0-100
+  contextSwitches: number;
+  timeSeries?: TimeSeries<number>; // Optional detailed trace
+}
+
+interface MemoryMetrics {
+  rss: number; // Resident Set Size (bytes)
+  vms: number; // Virtual Memory Size (bytes)
+  heap: number; // Heap usage (bytes)
+  external: number; // External memory (bytes)
+  peak: number; // Peak memory usage (bytes)
+  timeSeries?: TimeSeries<number>;
+}
+
+interface IOMetrics {
+  readOps: number;
+  writeOps: number;
+  readBytes: number;
+  writeBytes: number;
+  readLatency: number; // avg ms
+  writeLatency: number; // avg ms
+  timeSeries?: TimeSeries<IOSample>;
+}
+
+interface IOSample {
+  timestamp: number;
+  readOps: number;
+  writeOps: number;
+}
+
+interface DiskMetrics {
+  initialSize: number; // bytes
+  finalSize: number; // bytes
+  delta: number; // bytes
+  inodes: number;
+}
+
+interface TimeSeries<T> {
+  interval: number; // ms between samples
+  samples: T[];
+}
+```
+
+### 5. Processed Results
+
+```typescript
+interface ProcessedResult {
+  // Test identification
+  testSuite: string;
+  testName: string;
+  operation: string;
+  timestamp: string;
+
+  // Aggregated metrics by VCS type
+  jujutsu: PerformanceStats;
+  git: PerformanceStats;
+  gitWorktrees: PerformanceStats;
+
+  // Comparative analysis
+  comparison: {
+    jjVsGit: ComparisonMetrics;
+    jjVsGitWorktrees: ComparisonMetrics;
+    gitVsGitWorktrees: ComparisonMetrics;
+  };
+
+  // Quality metrics
+  quality: {
+    reliability: number; // Success rate 0-1
+    variance: number; // Coefficient of variation
+    outliers: number; // Number of outliers detected
+  };
+
+  // Insights
+  insights: {
+    winner: 'jujutsu' | 'git' | 'git-worktrees';
+    confidence: number; // 0-1
+    recommendations: Recommendation[];
+    bottlenecks: Bottleneck[];
+  };
+
+  // Learning data
+  learning: {
+    reward: number; // 0-1
+    patterns: Pattern[];
+    historicalComparison: TrendAnalysis;
+  };
+}
+
+interface PerformanceStats {
+  // Central tendency
+  mean: number;
+  median: number;
+  mode?: number;
+
+  // Dispersion
+  stdDev: number;
+  variance: number;
+  range: [number, number]; // [min, max]
+
+  // Percentiles
+  percentiles: {
+    p25: number;
+    p50: number;
+    p75: number;
+    p90: number;
+    p95: number;
+    p99: number;
+  };
+
+  // Sample info
+  sampleSize: number;
+  validSamples: number;
+  outliers: number[];
+
+  // Distribution
+  distribution: {
+    skewness: number;
+    kurtosis: number;
+    normality: boolean; // Shapiro-Wilk test
+  };
+}
+
+interface ComparisonMetrics {
+  // Performance ratios
+  speedupFactor: number; // baseline / comparison
+  memoryRatio: number; // comparison / baseline
+  ioEfficiency: number; // ops per byte
+
+  // Statistical significance
+  statistical: {
+    significant: boolean;
+    pValue: number;
+    confidenceInterval: [number, number];
+    effectSize: number; // Cohen's d
+    power: number; // Statistical power
+  };
+
+  // Practical significance
+  practical: {
+    absoluteDifference: number;
+    relativeDifference: number; // percentage
+    threshold: number; // Minimum meaningful difference
+    meaningful: boolean;
+  };
+}
+
+interface Recommendation {
+  id: string;
+  priority: 'low' | 'medium' | 'high' | 'critical';
+  category: 'performance' | 'quality' | 'security' | 'usability';
+  title: string;
+  description: string;
+  rationale: string;
+  expectedImpact: {
+    metric: string;
+    improvement: number; // percentage or absolute
+    confidence: number; // 0-1
+  };
+  implementation: {
+    effort: 'low' | 'medium' | 'high';
+    steps: string[];
+    risks: string[];
+  };
+}
+
+interface Bottleneck {
+  id: string;
+  type: 'cpu' | 'memory' | 'io' | 'algorithm';
+  location: string; // Code path or operation
+  severity: number; // 0-1
+  impact: {
+    timePercentage: number; // % of total time
+    occurences: number;
+  };
+  optimization: {
+    technique: string;
+    expectedGain: number; // percentage
+    complexity: 'trivial' | 'moderate' | 'complex';
+  };
+}
+
+interface Pattern {
+  type: 'performance' | 'error' | 'usage';
+  description: string;
+  frequency: number;
+  examples: string[];
+}
+
+interface TrendAnalysis {
+  direction: 'improving' | 'degrading' | 'stable';
+  slope: number; // Rate of change
+  r2: number; // Goodness of fit
+  forecast: {
+    nextValue: number;
+    confidence: number;
+  };
+}
+```
